class Solution:
    def sortList(self, head: ListNode) -> ListNode:
        if not head: return head
        if len(head) == 1: return head

        mid = self.getMiddle(head)
        mid_prev = self.getPrevNode(head, mid)

        second = mid.next
        mid.next = None
        second_prev = mid_prev

        left = self.sortList(head)
        right = self.sortList(second)

        return self.merge(left, right)

    def getMiddle(self, head: ListNode) -> ListNode:
        slow = head
        fast = head
        while fast.next and fast.next.next:
            slow = slow.next
            fast = fast.next.next
        return slow

    def getPrevNode(self, head: ListNode, node: ListNode) -> ListNode:
        current = head
        while current.next != node:
            current = current.next
        return current

    def merge(self, a: ListNode, b: ListNode) -> ListNode:
        dummy = ListNode(0)
        current = dummy
        while a and b:
            if a.val < b.val:
                current.next = a
                a = a.next
            else:
                current.next = b
                b = b.next
            current = current.next
        if a:
            current.next = a
        else:
            current.next = b
        return dummy.next

